package github.chains;

import spoon.Launcher;
import spoon.processing.Processor;
import spoon.reflect.CtModel;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.reference.CtTypeReference;

import java.util.List;

/**
 * Generic Spoon transformation to fix Mockito when() method compatibility issues
 * for Mockito 5.1.1 breaking changes.
 */
public class Main {
    public static void main(String[] args) {
        // Create a Spoon launcher
        Launcher launcher = new Launcher();

        // Set the source directory to process
        launcher.addInputResource("/workspace/bval");

        // Set the output directory
        launcher.setSourceOutputDirectory("/workspace/bval-transformed");

        // Add the processor to fix Mockito when() method calls
        launcher.addProcessor(new MockitoWhenFixer());

        // Build the model
        CtModel model = launcher.buildModel();

        // Process the model
        launcher.process();

        // Print results
        System.out.println("Transformation completed successfully!");
    }
}

/**
 * Processor to fix Mockito when() method invocations that might have compatibility issues
 */
class MockitoWhenFixer implements Processor<CtInvocation<?>> {
    @Override
    public void process(CtInvocation<?> invocation) {
        // Check if this is a Mockito when() method call
        CtExecutableReference<?> executableRef = invocation.getExecutable();
        if (executableRef != null) {
            String methodName = executableRef.getSimpleName();
            if ("when".equals(methodName)) {
                // Get the method's declaring type
                CtTypeReference<?> declaringType = executableRef.getDeclaringType();
                if (declaringType != null) {
                    String typeName = declaringType.getQualifiedName();
                    if (typeName.startsWith("org.mockito.Mockito")) {
                        // This is a Mockito when() call - we could add specific fixes here
                        // For now, we're just demonstrating the structure
                        System.out.println("Found Mockito when() call: " + invocation.toString());
                    }
                }
            }
        }
    }
}

